let state = null;

export function initialize(element, dotNetRef, timeoutMs) {
    const events = ["mousemove", "keydown", "click", "scroll"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }
        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnActiveCallback");
        }
        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnIdleCallback");
        }, timeoutMs);
    }

    for (const evt of events) {
        element.addEventListener(evt, resetTimer, { passive: true });
    }

    // Start the initial timer
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnIdleCallback");
    }, timeoutMs);

    state = { element, events, resetTimer, timerId: () => timerId, clearTimer: () => { clearTimeout(timerId); timerId = null; } };
}

export function dispose() {
    if (state) {
        state.clearTimer();
        for (const evt of state.events) {
            state.element.removeEventListener(evt, state.resetTimer);
        }
        state = null;
    }
}

